import { Section } from "@/components/ui/Section";
import { engineeringProjects } from "@/data/projects";
import { TechTag } from "@/components/ui/TechTag";

export function FullStackSection() {
  return (
    <Section id="fullstack">
      <div className="flex flex-col gap-10 lg:flex-row lg:items-start">
        <div className="lg:w-2/5">
          <h1 className="text-sm font-semibold uppercase tracking-[0.22em] text-emerald-300">
            Engineering Systems
          </h1>
          <p className="mt-3 text-2xl font-semibold tracking-tight text-slate-50 md:text-3xl">
            Full stack architectures built for real constraints.
          </p>
          <p className="mt-4 text-sm text-slate-400">
            Each project is treated as a system: clear problem framing, explicit
            constraints, and intentional trade-offs — not a feature checklist.
          </p>
        </div>

        <div className="grid flex-1 grid-cols-1 gap-5 md:grid-cols-2">
          {engineeringProjects.map((project) => (
            <article
              key={project.id}
              className="glass-surface card-hover spotlight-parent relative flex flex-col rounded-2xl p-5"
              data-cursor="card"
              onMouseMove={(event) => {
                const target = event.currentTarget;
                const rect = target.getBoundingClientRect();
                const x = ((event.clientX - rect.left) / rect.width) * 100;
                const y = ((event.clientY - rect.top) / rect.height) * 100;
                target.style.setProperty("--spotlight-x", `${x}%`);
                target.style.setProperty("--spotlight-y", `${y}%`);
              }}
            >
              <div className="spotlight-mask" />
              <h2 className="text-sm font-semibold text-slate-50">
                {project.title}
              </h2>
              <p className="mt-3 text-[0.78rem] font-medium uppercase tracking-[0.18em] text-slate-500">
                Problem
              </p>
              <p className="mt-1 text-[0.8rem] leading-relaxed text-slate-300">
                {project.problem}
              </p>
              <p className="mt-3 text-[0.78rem] font-medium uppercase tracking-[0.18em] text-slate-500">
                System Design
              </p>
              <p className="mt-1 text-[0.8rem] leading-relaxed text-slate-300">
                {project.solution}
              </p>
              <p className="mt-3 text-[0.78rem] font-medium uppercase tracking-[0.18em] text-slate-500">
                Impact
              </p>
              <p className="mt-1 text-[0.8rem] leading-relaxed text-slate-300">
                {project.impact}
              </p>

              <div className="mt-4 flex flex-wrap gap-1.5">
                {project.tech.map((tech) => (
                  <TechTag key={tech} label={tech} />
                ))}
              </div>
            </article>
          ))}
        </div>
      </div>
    </Section>
  );
}

