import { Section } from "@/components/ui/Section";
import { ProgressRing } from "@/components/ui/ProgressRing";

export function InternshipSection() {
  return (
    <Section id="internship" className="pt-4">
      <div className="grid gap-8 md:grid-cols-[minmax(0,3fr)_minmax(0,2fr)] md:items-center">
        <div>
          <h2 className="text-sm font-semibold uppercase tracking-[0.22em] text-emerald-300">
            Internship Experience
          </h2>
          <p className="mt-3 text-xl font-semibold tracking-tight text-slate-50 md:text-2xl">
            Shipping real work inside production environments.
          </p>
          <p className="mt-4 text-sm text-slate-400">
            Focused on improving performance, tightening observability, and
            integrating intelligent behaviour without breaking the reliability
            expectations of the system.
          </p>
          <ul className="mt-4 space-y-2 text-[0.82rem] text-slate-300">
            <li>• Worked across the stack: APIs, UI surfaces and automation.</li>
            <li>• Helped diagnose performance regressions with metrics-first thinking.</li>
            <li>• Contributed to CI/CD workflows and deployment safety.</li>
          </ul>
        </div>
        <div className="flex justify-center md:justify-end">
          <ProgressRing
            progress={86}
            label="Full Stack Internship"
            caption="Confidence that you can operate inside existing, real-world systems — not just greenfield prototypes."
          />
        </div>
      </div>
    </Section>
  );
}

